        ///<summary>
        ///proxiedSetTokenPayoutRatio is meant to be called by pools != 1 - calling US, pool #1
        ///We need to verify that we are in fact being called by another of OUR pools (not us)
        ///and then we'll call the validator on their behalf to update the token payouts
        ///</summary>
        /// <param name="poolKey">- ValidatorPoolKey tuple ValidatorPoolKey</param>
        public async Task<Structs.PoolTokenPayoutRatio> ProxiedSetTokenPayoutRatio(Structs.ValidatorPoolKey poolKey, Account _tx_sender, ulong? _tx_fee, string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp)
        {
            _tx_boxes ??= new List<BoxRef>();
            _tx_transactions ??= new List<Transaction>();
            _tx_assets ??= new List<ulong>();
            _tx_apps ??= new List<ulong>();
            _tx_accounts ??= new List<Address>();
            byte[] abiHandle = { 12, 34, 69, 225 };

            var result = await base.CallApp(new List<object> { abiHandle, poolKey }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
            var lastLogBytes = result.Last();
            if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
            return Structs.PoolTokenPayoutRatio.Parse(lastLogBytes.Skip(4).ToArray());

        }

